import jakarta.persistence.*;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Entity @Table(name = "tickets")
public class Ticket {
    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String eventName;
    private int available;

    @Version
    private int version;  // ← Hibernate adds AND version=? to every UPDATE

    protected Ticket() {}
    public Ticket(String event, int qty) { eventName=event; available=qty; }

    public Long getId()       { return id; }
    public int getAvailable() { return available; }
    public int getVersion()   { return version; }
    public void setAvailable(int a) { available = a; }
}

public interface TicketRepository extends JpaRepository<Ticket, Long> {}

public enum BookingResult { SUCCESS, SOLD_OUT }

@Service
public class TicketService {
    private final TicketRepository repo;
    TicketService(TicketRepository r) { repo = r; }

    @Transactional
    public BookingResult bookTicket(Long ticketId) {
        Ticket t = repo.findById(ticketId).orElseThrow();

        if (t.getAvailable() <= 0) return BookingResult.SOLD_OUT;

        t.setAvailable(t.getAvailable() - 1);
        repo.save(t);
        // Hibernate SQL:
        // UPDATE tickets SET available=N-1, version=V+1 WHERE id=? AND version=V
        // If another thread already changed version: 0 rows → OptimisticLockException

        return BookingResult.SUCCESS;
    }
}

