import org.springframework.retry.annotation.*;
import jakarta.persistence.OptimisticLockException;
import org.springframework.orm.ObjectOptimisticLockingFailureException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class TicketServiceRetryable {
    private final TicketRepository repo;
    TicketServiceRetryable(TicketRepository r) { repo = r; }

    @Retryable(
        value = {OptimisticLockException.class,
                 ObjectOptimisticLockingFailureException.class},
        maxAttempts = 3,
        backoff = @Backoff(delay = 50, multiplier = 2.0)
        // Retry delays: attempt 1 (immediate), attempt 2 (+50ms), attempt 3 (+100ms)
    )
    @Transactional
    public BookingResult bookTicket(Long ticketId) {
        Ticket t = repo.findById(ticketId).orElseThrow();
        if (t.getAvailable() <= 0) return BookingResult.SOLD_OUT;
        t.setAvailable(t.getAvailable() - 1);
        repo.save(t);
        return BookingResult.SUCCESS;
    }

    @Recover
    public BookingResult recoverFromLockFailure(
            ObjectOptimisticLockingFailureException ex, Long ticketId) {
        // Called after all retries exhausted:
        System.err.println("All 3 attempts failed for ticket " + ticketId + ": " + ex.getMessage());
        return BookingResult.SOLD_OUT;  // or throw an exception
    }
}

