import jakarta.persistence.*;
import org.springframework.data.jpa.repository.*;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Entity @Table(name="inventory_items")
public class InventoryItem {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;
    @Column(nullable=false, unique=true) private String sku;
    @Column(nullable=false) private int stockQty;

    protected InventoryItem(){}
    public InventoryItem(String sku, int qty){ this.sku=sku; stockQty=qty; }
    public Long getId()     { return id; }
    public String getSku()  { return sku; }
    public int getStockQty(){ return stockQty; }
    public void setStockQty(int q){ stockQty=q; }
}

public interface InventoryRepository extends JpaRepository<InventoryItem,Long> {

    // @Lock PESSIMISTIC_WRITE: SELECT ... FROM inventory_items WHERE sku=? FOR UPDATE
    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("SELECT i FROM InventoryItem i WHERE i.sku = :sku")
    java.util.Optional<InventoryItem> findBySkuWithLock(@Param("sku") String sku);

    // Without lock (for reads that don't need exclusive access):
    java.util.Optional<InventoryItem> findBySku(String sku);
}

@Service
public class InventoryService {
    private final InventoryRepository repo;
    InventoryService(InventoryRepository r){ repo=r; }

    @Transactional  // REQUIRED: lock held until this transaction commits!
    public boolean reserve(String sku, int qty) {
        // SELECT ... FOR UPDATE: acquires exclusive row lock
        InventoryItem item = repo.findBySkuWithLock(sku)
            .orElseThrow(() -> new IllegalArgumentException("SKU not found: " + sku));

        if (item.getStockQty() < qty) return false;  // insufficient stock

        item.setStockQty(item.getStockQty() - qty);
        // Lock released when this method returns and transaction commits
        return true;
    }
}

// GENERATED SQL:
// SELECT id, sku, stock_qty FROM inventory_items WHERE sku=? FOR UPDATE
//                                                     ← FOR UPDATE = exclusive lock
// Thread B calling reserve('SKU001', 2):
//   → Blocks at FOR UPDATE until Thread A's transaction commits
//   → Then reads FRESH data (Thread A's update already committed)
//   → No race condition!

