import jakarta.persistence.*;
import org.springframework.boot.test.autoconfigure.orm.jpa.*;
import org.springframework.beans.factory.annotation.*;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.orm.ObjectOptimisticLockingFailureException;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Entity class OLProduct {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String name; double price;
    @Version int version;
    protected OLProduct(){}
    OLProduct(String n, double p){name=n;price=p;}
    Long getId(){return id;} double getPrice(){return price;} int getVersion(){return version;}
    void setPrice(double p){price=p;}
}
interface OLProductRepo extends JpaRepository<OLProduct,Long>{}

@DataJpaTest
class OptimisticLockTest {
    @Autowired OLProductRepo repo;
    @Autowired TestEntityManager testEm;

    @Test
    void conflictingUpdates_secondFails() {
        // Arrange: save initial product (version=0)
        OLProduct saved = repo.save(new OLProduct("Keyboard", 1999));
        Long id = saved.getId();
        testEm.flush(); testEm.clear();

        // Simulate Thread A: loads and modifies (version=0)
        OLProduct threadA = repo.findById(id).orElseThrow();
        assertEquals(0, threadA.getVersion());
        threadA.setPrice(1899);

        // Thread A commits successfully:
        repo.save(threadA); testEm.flush(); testEm.clear();
        // Now DB: price=1899, version=1

        // Simulate Thread B: loaded BEFORE Thread A committed (stale version=0)
        OLProduct threadB = new OLProduct("Keyboard", 1999);
        // Manually set the ID and version to simulate stale load:
        // (In real app, threadB loaded before threadA saved)
        // Use EntityManager to get a detached stale copy:
        testEm.clear();
        OLProduct stale = repo.findById(id).orElseThrow();
        testEm.clear();
        // Simulate stale: use EntityManager merge with old version
        stale.setPrice(2099);
        stale.version = 0; // force stale version (simulate Thread B loaded before Thread A)

        // Thread B tries to save → should fail:
        assertThrows(ObjectOptimisticLockingFailureException.class, () -> {
            repo.save(stale);
            testEm.flush();  // force SQL execution
        });

        // Verify: DB still has Thread A's price:
        testEm.clear();
        OLProduct final1 = repo.findById(id).orElseThrow();
        assertEquals(1899, final1.getPrice(), 0.01, "Thread A's price should persist");
        assertEquals(1, final1.getVersion(), "Version should be 1 after Thread A's update");
    }
}

