import java.time.LocalDateTime;

@Entity @Table(name="audit_logs")
class AuditLog {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String operation; String entityId; String userId; boolean success;
    LocalDateTime timestamp=LocalDateTime.now();
    protected AuditLog(){}
    AuditLog(String op,String eid,String uid,boolean ok){operation=op;entityId=eid;userId=uid;success=ok;}
    Long getId(){return id;} boolean isSuccess(){return success;} String getOperation(){return operation;}
}
@Entity @Table(name="audit_orders")
class AuditOrder {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String userId; double total;
    protected AuditOrder(){}
    AuditOrder(String uid,double t){userId=uid;total=t;}
    Long getId(){return id;}
}
interface AuditLogRepo extends JpaRepository<AuditLog,Long>{}
interface AuditOrderRepo extends JpaRepository<AuditOrder,Long>{}

@Service
class AuditService {
    private final AuditLogRepo repo;
    AuditService(AuditLogRepo r){repo=r;}

    @Transactional(propagation=Propagation.REQUIRES_NEW)  // OWN transaction!
    public void log(String op, String eid, String uid, boolean ok) {
        repo.save(new AuditLog(op,eid,uid,ok));
        // Even if caller's transaction rolls back, this COMMITS independently!
    }
}

@Service
class OrderService {
    private final AuditOrderRepo or; private final AuditService audit;
    OrderService(AuditOrderRepo o,AuditService a){or=o;audit=a;}

    @Transactional
    public AuditOrder placeOrder(String uid, double total, boolean paymentFails) {
        AuditOrder order=or.save(new AuditOrder(uid,total));
        if(paymentFails) {
            audit.log("ORDER_FAILED",String.valueOf(order.getId()),uid,false);
            throw new RuntimeException("Payment failed!");  // rolls back order save
        }
        audit.log("ORDER_PLACED",String.valueOf(order.getId()),uid,true);
        return order;
    }
}

@DataJpaTest @Import({AuditService.class,OrderService.class})
class AuditPropagationTest {
    @Autowired OrderService svc;
    @Autowired AuditLogRepo auditRepo;
    @Autowired AuditOrderRepo orderRepo;
    @Autowired TestEntityManager testEm;

    @Test void orderFails_auditLogPersists() {
        assertThrows(RuntimeException.class,()->svc.placeOrder("U01",999,true));
        testEm.flush(); testEm.clear();
        assertEquals(0,orderRepo.count(),"Order should be rolled back");
        assertEquals(1,auditRepo.count(),"Audit log should persist despite rollback");
        assertFalse(auditRepo.findAll().get(0).isSuccess());
    }
    @Test void orderSucceeds_bothPersist() {
        svc.placeOrder("U01",999,false);
        testEm.flush(); testEm.clear();
        assertEquals(1,orderRepo.count());
        assertEquals(1,auditRepo.count());
        assertTrue(auditRepo.findAll().get(0).isSuccess());
    }
}

