import jakarta.persistence.*;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.boot.test.autoconfigure.orm.jpa.*;
import org.springframework.context.annotation.Import;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.io.IOException;

@Entity @Table(name="processed_records")
class ProcessedRecord {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String data;
    protected ProcessedRecord(){}
    ProcessedRecord(String d){data=d;}
    Long getId(){return id;}
}
interface ProcessedRepo extends JpaRepository<ProcessedRecord,Long>{}

@Service
class FileServiceWithGap {
    private final ProcessedRepo repo;
    FileServiceWithGap(ProcessedRepo r){repo=r;}

    // DEFAULT @Transactional: checked IOException does NOT trigger rollback!
    @Transactional  // ← only rolls back on RuntimeException
    public void processAndSaveNoRollback(String data) throws IOException {
        repo.save(new ProcessedRecord(data));  // saved to DB...
        throw new IOException("File write failed!");  // ...but rollback NOT triggered!
        // Result: record SAVED to DB, but IOException thrown to caller
    }

    // FIXED: rollbackFor=Exception.class includes checked exceptions:
    @Transactional(rollbackFor = Exception.class)
    public void processAndSaveWithRollback(String data) throws IOException {
        repo.save(new ProcessedRecord(data));  // saved...
        throw new IOException("File write failed!");  // rollback triggered!
        // Result: record NOT saved (rolled back), IOException thrown to caller
    }
}

@DataJpaTest @Import(FileServiceWithGap.class)
class RollbackForTest {
    @Autowired FileServiceWithGap svc;
    @Autowired ProcessedRepo repo;
    @Autowired TestEntityManager testEm;

    @Test void withoutRollbackFor_checkedExceptionDoesNotRollback() {
        assertThrows(IOException.class, () -> svc.processAndSaveNoRollback("data1"));
        testEm.flush(); testEm.clear();
        assertEquals(1, repo.count(),  // ← record IS saved despite IOException!
            "Without rollbackFor: record persists even though exception was thrown");
    }

    @Test void withRollbackFor_checkedExceptionRollsBack() {
        assertThrows(IOException.class, () -> svc.processAndSaveWithRollback("data2"));
        testEm.flush(); testEm.clear();
        assertEquals(0, repo.count(),  // ← record NOT saved (rolled back)
            "With rollbackFor=Exception.class: record rolled back on IOException");
    }
}

