import jakarta.persistence.*;
import org.springframework.data.jpa.repository.*;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.Optional;

public interface TimeoutTicketRepo extends JpaRepository<Ticket, Long> {

    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @QueryHints({
        @QueryHint(
            name = "jakarta.persistence.lock.timeout",
            value = "3000"  // 3000ms = 3 seconds
        )
    })
    @Query("SELECT t FROM Ticket t WHERE t.id = :id")
    Optional<Ticket> findByIdWithLockAndTimeout(@Param("id") Long id);
}

public enum BookingResult { SUCCESS, SOLD_OUT, TIMEOUT, ERROR }

@Service
public class TicketServiceTimeout {
    private final TimeoutTicketRepo repo;
    TicketServiceTimeout(TimeoutTicketRepo r) { repo = r; }

    @Transactional
    public BookingResult bookWithTimeout(Long ticketId) {
        try {
            Ticket t = repo.findByIdWithLockAndTimeout(ticketId).orElseThrow();

            if (t.getAvailable() <= 0) return BookingResult.SOLD_OUT;
            t.setAvailable(t.getAvailable() - 1);
            // Lock held until transaction commits
            return BookingResult.SUCCESS;

        } catch (LockTimeoutException e) {
            // Could not acquire lock within 3 seconds:
            System.err.println("Lock timeout for ticket " + ticketId + ": " + e.getMessage());
            return BookingResult.TIMEOUT;  // return immediately, don't leave user waiting
        } catch (PessimisticLockException e) {
            // Lock acquisition failed immediately (some DBs throw this instead of LockTimeout):
            return BookingResult.TIMEOUT;
        }
    }
}

// What happens at timeout:
// LockTimeoutException: could not obtain pessimistic lock on rows in table 'tickets'
//   → PostgreSQL: ERROR: canceling statement due to lock timeout
//   → Application: LockTimeoutException caught → return TIMEOUT
// Without timeout: thread blocked indefinitely → thread pool exhaustion under deadlock!

