import org.springframework.boot.test.autoconfigure.orm.jpa.*;
import org.springframework.context.annotation.Import;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;
import java.math.RoundingMode;

@Entity @Table(name="z_positions")
class ZPosition {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    @Column(nullable=false) String userId;
    @Column(nullable=false) String symbol;
    @Column(nullable=false) int totalQty;
    @Column(nullable=false,precision=12,scale=2) BigDecimal avgPrice;
    @Version int version;
    protected ZPosition(){}
    ZPosition(String u,String s,int q,BigDecimal p){userId=u;symbol=s;totalQty=q;avgPrice=p;}
    Long getId(){return id;} int getTotalQty(){return totalQty;}
    BigDecimal getAvgPrice(){return avgPrice;} int getVersion(){return version;}
    void applyBuy(int qty,BigDecimal price){
        BigDecimal totalVal=avgPrice.multiply(BigDecimal.valueOf(totalQty))
            .add(price.multiply(BigDecimal.valueOf(qty)));
        totalQty+=qty;
        avgPrice=totalVal.divide(BigDecimal.valueOf(totalQty),2,RoundingMode.HALF_UP);
    }
}
interface ZPositionRepo extends JpaRepository<ZPosition,Long>{
    java.util.Optional<ZPosition> findByUserIdAndSymbol(String uid,String sym);
}

@Service
class ZPositionService {
    private final ZPositionRepo repo;
    ZPositionService(ZPositionRepo r){repo=r;}

    @Retryable(value={ObjectOptimisticLockingFailureException.class},
               maxAttempts=5,backoff=@Backoff(delay=50,multiplier=2))
    @Transactional
    ZPosition applyBuy(String uid,String sym,int qty,BigDecimal price){
        ZPosition pos=repo.findByUserIdAndSymbol(uid,sym)
            .orElseGet(()->new ZPosition(uid,sym,0,price));
        pos.applyBuy(qty,price);
        return repo.save(pos);
    }
}

@DataJpaTest @Import(ZPositionService.class)
class ZPositionTest {
    @Autowired ZPositionService svc;
    @Autowired ZPositionRepo repo;
    @Autowired TestEntityManager testEm;

    @Test void twoBuys_accumulateCorrectly(){
        svc.applyBuy("U01","TCS",10,new BigDecimal("3890"));
        svc.applyBuy("U01","TCS",5, new BigDecimal("3900"));
        testEm.flush(); testEm.clear();
        ZPosition pos=repo.findByUserIdAndSymbol("U01","TCS").orElseThrow();
        assertEquals(15,pos.getTotalQty());
        // Weighted avg: (3890*10 + 3900*5) / 15 = 58400/15 = 3893.33
        assertEquals(new BigDecimal("3893.33"),pos.getAvgPrice());
    }
    @Test void versionIncrements(){
        ZPosition p=svc.applyBuy("U02","INFY",10,new BigDecimal("1560"));
        int v1=p.getVersion();
        svc.applyBuy("U02","INFY",5,new BigDecimal("1570"));
        testEm.flush(); testEm.clear();
        ZPosition loaded=repo.findByUserIdAndSymbol("U02","INFY").orElseThrow();
        assertTrue(loaded.getVersion()>v1,"Version should increment after second update");
    }
}

