@Entity @Table(name="bms_seats")
class Seat {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String eventId; int row; int col;
    boolean booked=false; String bookedByUserId;
    @Version int version;
    protected Seat(){}
    Seat(String eid,int r,int c){eventId=eid;row=r;col=c;}
    Long getId(){return id;} boolean isBooked(){return booked;}
