@Entity @Table(name="dl_accounts")
class DLAccount {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    String owner; double balance;
    protected DLAccount(){}
    DLAccount(String o,double b){owner=o;balance=b;}
    Long getId(){return id;} double getBalance(){return balance;}
    void debit(double a){if(a>balance)throw new IllegalStateException("Insufficient");balance-=a;}
    void credit(double a){balance+=a;}
}
interface DLAccountRepo extends JpaRepository<DLAccount,Long>{
    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("SELECT a FROM DLAccount a WHERE a.id=:id")
    Optional<DLAccount> findByIdWithLock(@Param("id") Long id);
}

// DEADLOCK SCENARIO (BAD):
// Thread A: lock account 1 → lock account 2 → transfer A→B
// Thread B: lock account 2 → lock account 1 → transfer B→A
// Thread A holds lock on 1, waits for 2
// Thread B holds lock on 2, waits for 1  ← DEADLOCK!

@Service
class AccountTransferService {
    private final DLAccountRepo repo;
    AccountTransferService(DLAccountRepo r){repo=r;}

    @Transactional
    public void transfer(Long fromId,Long toId,double amount){
        // DEADLOCK PREVENTION: always lock in ascending ID order!
        Long firstId  = Math.min(fromId,toId);
        Long secondId = Math.max(fromId,toId);

        DLAccount first  = repo.findByIdWithLock(firstId).orElseThrow();
        DLAccount second = repo.findByIdWithLock(secondId).orElseThrow();

        // Now determine which is 'from' and which is 'to':
        DLAccount from = fromId.equals(firstId) ? first : second;
        DLAccount to   = fromId.equals(firstId) ? second : first;

        from.debit(amount);
        to.credit(amount);
        // No deadlock: both threads lock id=1 first, then id=2
    }
}

@DataJpaTest @Import(AccountTransferService.class)
class DeadlockFreeTest {
    @Autowired AccountTransferService svc;
    @Autowired DLAccountRepo repo;
    @Autowired TestEntityManager testEm;

    @Test void transfer_correctBalances(){
        DLAccount a=testEm.persistAndFlush(new DLAccount("Aisha",1000));
        DLAccount b=testEm.persistAndFlush(new DLAccount("Raj",500));
        testEm.clear();
        svc.transfer(a.getId(),b.getId(),300);
        testEm.flush(); testEm.clear();
        assertEquals(700,repo.findById(a.getId()).orElseThrow().getBalance(),0.01);
        assertEquals(800,repo.findById(b.getId()).orElseThrow().getBalance(),0.01);
    }
    @Test void transfer_insufficientFunds_throws(){
        DLAccount a=testEm.persistAndFlush(new DLAccount("Aisha",100));
        DLAccount b=testEm.persistAndFlush(new DLAccount("Raj",500));
        testEm.clear();
        assertThrows(IllegalStateException.class,()->svc.transfer(a.getId(),b.getId(),500));
    }
}

import jakarta.persistence.*;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.*;
import org.springframework.retry.annotation.*;
import org.springframework.orm.ObjectOptimisticLockingFailureException;
import org.springframework.boot.test.autoconfigure.orm.jpa.*;
import org.springframework.context.annotation.Import;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;
import java.time.LocalDateTime;

@Entity @Table(name="rp_payment_orders")
class RPPaymentOrder {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    @Column(nullable=false) String merchantId;
    @Column(nullable=false,precision=14,scale=2) BigDecimal amount;
    @Column(nullable=false) String status="PENDING";
    @Version int version;
    protected RPPaymentOrder(){}
    RPPaymentOrder(String mid,BigDecimal amt){merchantId=mid;amount=amt;}
    Long getId(){return id;} String getStatus(){return status;} int getVersion(){return version;}
    void capture(){if(!"PENDING".equals(status))throw new IllegalStateException("Cannot capture: status="+status);status="CAPTURED";}
    void fail(){status="FAILED";}
}
@Entity @Table(name="rp_payment_audits")
class RPPaymentAudit {
    @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id;
    Long orderId; String action; boolean success; LocalDateTime at=LocalDateTime.now();
    protected RPPaymentAudit(){}
    RPPaymentAudit(Long oid,String a,boolean ok){orderId=oid;action=a;success=ok;}
    boolean isSuccess(){return success;} String getAction(){return action;}
}
interface RPPaymentRepo extends JpaRepository<RPPaymentOrder,Long>{}
interface RPAuditRepo  extends JpaRepository<RPPaymentAudit,Long>{
    java.util.List<RPPaymentAudit> findByOrderId(Long orderId);
}

@Service
class RPAuditService {
    private final RPAuditRepo repo;
    RPAuditService(RPAuditRepo r){repo=r;}
    @Transactional(propagation=Propagation.REQUIRES_NEW)
    public void log(Long orderId,String action,boolean ok){
        repo.save(new RPPaymentAudit(orderId,action,ok));
    }
}

@Service
class RPPaymentService {
    private final RPPaymentRepo pr; private final RPAuditService audit;
    RPPaymentService(RPPaymentRepo p,RPAuditService a){pr=p;audit=a;}

    @Retryable(value=ObjectOptimisticLockingFailureException.class,maxAttempts=3,backoff=@Backoff(delay=50))
    @Transactional(rollbackFor=Exception.class)
    public RPPaymentOrder capture(Long orderId){
        RPPaymentOrder order=pr.findById(orderId).orElseThrow();
        order.capture();  // throws if not PENDING
        RPPaymentOrder saved=pr.save(order);
        audit.log(orderId,"CAPTURE",true);
        return saved;
    }

    @Retryable(value=ObjectOptimisticLockingFailureException.class,maxAttempts=3,backoff=@Backoff(delay=50))
    @Transactional(rollbackFor=Exception.class)
    public RPPaymentOrder refund(Long orderId){
        RPPaymentOrder order=pr.findById(orderId).orElseThrow();
        if(!"CAPTURED".equals(order.getStatus()))throw new IllegalStateException("Cannot refund");
        order.fail();
        RPPaymentOrder saved=pr.save(order);
        audit.log(orderId,"REFUND",true);
        return saved;
    }
}

@DataJpaTest @Import({RPAuditService.class,RPPaymentService.class})
